#!/usr/bin/env node
// Sync agent-facing "highlight" rules from docs/ai/** into per-tool entry files.
//
// Source of truth: HTML-comment-tagged blocks inside AGENTS.md and docs/ai/**.
//   <!-- agent-rules:start id="tailwind-v4-important" -->
//   - Tailwind v4: important modifier is a suffix (`mb-6!`), not a prefix.
//   <!-- agent-rules:end -->
//
// Destination files declare an auto-generated section with sentinel markers:
//   <!-- AUTO-GENERATED:agent-rules:start -->
//   ...
//   <!-- AUTO-GENERATED:agent-rules:end -->
// Content outside those markers is preserved verbatim.
//
// Usage:
//   node scripts/build.agent-rules.mjs           # rewrite destinations
//   node scripts/build.agent-rules.mjs --check   # CI gate; non-zero on drift
//
// Adding a new highlight:
//   1. Wrap a markdown block in docs/ai/** with the marker pair above.
//   2. Add the id to the appropriate destination in DESTINATIONS below.
//   3. Run `node scripts/build.agent-rules.mjs`.

import { readdir, readFile, stat, writeFile } from 'node:fs/promises';
import { join, relative, resolve } from 'node:path';
import { fileURLToPath } from 'node:url';

const REPO_ROOT = resolve(fileURLToPath(import.meta.url), '..', '..');

const SOURCES = ['AGENTS.md', 'docs/ai'];

const DESTINATIONS = [
	{
		path: '.github/copilot-instructions.md',
		heading: 'Highlights synced from `docs/ai/**`',
		intro:
			"Bug-catching rules that this file's reader (Copilot's PR reviewer) " +
			"is otherwise unlikely to see, because it doesn't traverse the " +
			'`docs/ai/**` link graph. Source of truth lives in those files; this ' +
			'section is regenerated by `scripts/build.agent-rules.mjs` and gated ' +
			'in CI.',
		blockIds: ['tailwind-v4-important']
	}
];

const SENTINEL_START = '<!-- AUTO-GENERATED:agent-rules:start -->';
const SENTINEL_END = '<!-- AUTO-GENERATED:agent-rules:end -->';
const BLOCK_START_RE = /<!--\s*agent-rules:start\s+id="([^"]+)"\s*-->/g;
const BLOCK_END_RE = /<!--\s*agent-rules:end(?:\s+id="[^"]+")?\s*-->/;

async function walk(dir) {
	const out = [];
	for (const entry of await readdir(dir, { withFileTypes: true })) {
		const p = join(dir, entry.name);
		if (entry.isDirectory()) out.push(...(await walk(p)));
		else if (entry.isFile() && entry.name.endsWith('.md')) out.push(p);
	}
	return out;
}

async function collectSourceFiles() {
	const files = [];
	for (const s of SOURCES) {
		const abs = join(REPO_ROOT, s);
		let info;
		try {
			info = await stat(abs);
		} catch {
			continue;
		}
		if (info.isDirectory()) files.push(...(await walk(abs)));
		else if (info.isFile() && abs.endsWith('.md')) files.push(abs);
	}
	return files;
}

function stripFencedCode(text) {
	// Blank out fenced code blocks (``` … ``` and ~~~ … ~~~) so a documentation
	// example of the marker syntax inside a fence is not treated as a real
	// block. Lines are blanked individually so byte offsets line up with the
	// original text.
	const lines = text.split('\n');
	let openFence = null;
	for (let i = 0; i < lines.length; i++) {
		const fenceMatch = lines[i].match(/^(\s*)(`{3,}|~{3,})/);
		if (openFence === null) {
			if (fenceMatch) {
				openFence = fenceMatch[2][0];
				lines[i] = ''.padEnd(lines[i].length);
			}
		} else {
			const isClose =
				fenceMatch && fenceMatch[2][0] === openFence && /^\s*(`{3,}|~{3,})\s*$/.test(lines[i]);
			lines[i] = ''.padEnd(lines[i].length);
			if (isClose) openFence = null;
		}
	}
	return lines.join('\n');
}

function extractBlocks(text, sourcePath) {
	const scanText = stripFencedCode(text);
	const blocks = [];
	BLOCK_START_RE.lastIndex = 0;
	let match;
	while ((match = BLOCK_START_RE.exec(scanText)) !== null) {
		const id = match[1];
		const afterOpen = match.index + match[0].length;
		const rest = scanText.slice(afterOpen);
		const endMatch = rest.match(BLOCK_END_RE);
		if (!endMatch) {
			throw new Error(`Unterminated agent-rules block id="${id}" in ${sourcePath}`);
		}
		// Pull the *original* (un-stripped) content slice so code samples inside
		// a real block are preserved verbatim.
		const contentStart = afterOpen;
		const contentEnd = afterOpen + endMatch.index;
		const raw = text.slice(contentStart, contentEnd);
		blocks.push({ id, source: sourcePath, content: raw.trim() });
	}
	return blocks;
}

async function buildBlockMap() {
	const files = await collectSourceFiles();
	const map = new Map();
	for (const f of files) {
		const text = await readFile(f, 'utf8');
		for (const b of extractBlocks(text, relative(REPO_ROOT, f))) {
			if (map.has(b.id)) {
				const existing = map.get(b.id);
				throw new Error(
					`Duplicate agent-rules block id="${b.id}" in ${b.source} (already defined in ${existing.source})`
				);
			}
			map.set(b.id, b);
		}
	}
	return map;
}

function renderSection(destination, blockMap) {
	const lines = [SENTINEL_START, '', `## ${destination.heading}`, '', destination.intro, ''];
	for (const id of destination.blockIds) {
		const b = blockMap.get(id);
		if (!b) {
			throw new Error(`Destination ${destination.path} references unknown block id="${id}"`);
		}
		lines.push(b.content, '', `_Source: \`${b.source}\` (id: \`${id}\`)._`, '');
	}
	lines.push(SENTINEL_END);
	return lines.join('\n');
}

function spliceSection(current, newSection, destPath) {
	const startIdx = current.indexOf(SENTINEL_START);
	const endIdx = current.indexOf(SENTINEL_END);
	if (startIdx === -1 || endIdx === -1 || endIdx < startIdx) {
		throw new Error(
			`Destination ${destPath} is missing the AUTO-GENERATED sentinel pair. ` +
				`Add:\n\n${SENTINEL_START}\n${SENTINEL_END}\n\nwhere the generated block should live.`
		);
	}
	const before = current.slice(0, startIdx);
	const after = current.slice(endIdx + SENTINEL_END.length);
	return before + newSection + after;
}

async function main() {
	const check = process.argv.includes('--check');
	const blockMap = await buildBlockMap();
	const drift = [];
	for (const dest of DESTINATIONS) {
		const abs = join(REPO_ROOT, dest.path);
		const current = await readFile(abs, 'utf8');
		const section = renderSection(dest, blockMap);
		const next = spliceSection(current, section, dest.path);
		if (next === current) continue;
		if (check) {
			drift.push(dest.path);
		} else {
			await writeFile(abs, next);
			console.log(`updated ${dest.path}`);
		}
	}
	if (check && drift.length > 0) {
		console.error(
			`Agent-rules sync drift detected in:\n  - ${drift.join('\n  - ')}\n\n` +
				`Run \`node scripts/build.agent-rules.mjs\` and commit the result.`
		);
		process.exit(1);
	}
}

main().catch((err) => {
	console.error(err.message ?? err);
	process.exit(1);
});
